module S (input [7:0] in, output reg [7:0] out);
  always @(*) out = in;
endmodule

module top (input [31:0] in, output [31:0] out);
  S S_0 (in[31:24], out[31:24]),
    S_1 (in[23:16], out[23:16]),
    S_2 (in[15:8], out[15:8]),
    S_3 (in[7:0], out[7:0]);
endmodule

module S (input [7:0] in, output reg [7:0] out);
  always @(*)
    case (in)
      8'h00: out <= 8'h63;
      8'h01: out <= 8'h7c;
      8'h02: out <= 8'h77;
      default: out <= 8'h00;
    endcase
endmodule
